/**
 * @param {number} n The number of rows.
 * @param {number} m The number of columns.
 * @param {number[][]} sources Array of [r_i, c_i, color_i].
 * @return {number[][]} The final grid state.
 */
function solve(n, m, sources) {
    // Initialize distance grid (D) and final color grid (C_final)
    const INF = Infinity;
    const D = Array(n).fill(0).map(() => Array(m).fill(INF));
    const C_final = Array(n).fill(0).map(() => Array(m).fill(0));

    // Queue for BFS: stores [r, c]
    const queue = [];

    // 1. Initialization with sources
    for (const [r, c, color] of sources) {
        D[r][c] = 0;
        C_final[r][c] = color;
        queue.push([r, c]);
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    let head = 0;
    // 2. Multi-Source BFS
    while (head < queue.length) {
        const [r, c] = queue[head++];
        const d = D[r][c];
        // The color associated with the minimum time D[r][c]
        const c_propagating = C_final[r][c]; 

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const new_d = d + 1;

                if (new_d < D[nr][nc]) {
                    // Found a strictly shorter path (New minimum time)
                    D[nr][nc] = new_d;
                    C_final[nr][nc] = c_propagating;
                    queue.push([nr, nc]);

                } else if (new_d === D[nr][nc]) {
                    // Collision at minimum time (Tie in distance). Check for maximum color.
                    // c_propagating is one of the colors arriving at this minimum time.
                    C_final[nr][nc] = Math.max(C_final[nr][nc], c_propagating);
                }
            }
        }
    }

    return C_final;
}

