import java.util.ArrayDeque
import java.util.Queue

fun solve(n: Long, m: Long, sources: Array<Array<Long>>): Array<Array<Long>> {
    // Since N*M <= 10^5, we can safely cast dimensions to Int for array indexing.
    val N = n.toInt()
    val M = m.toInt()

    val INF: Long = Long.MAX_VALUE

    // D[r][c]: minimum time to reach (r, c)
    val D = Array(N) { LongArray(M) { INF } }

    // C_final[r][c]: final color of (r, c)
    val C_final = Array(N) { LongArray(M) { 0L } }

    // Queue for BFS: stores Pair<r, c>
    val queue: Queue<Pair<Int, Int>> = ArrayDeque()

    // 1. Initialization with sources
    for (source in sources) {
        val r = source[0].toInt()
        val c = source[1].toInt()
        val color = source[2]

        D[r][c] = 0L
        C_final[r][c] = color
        queue.add(Pair(r, c))
    }

    val directions = listOf(
        Pair(0, 1), Pair(0, -1), Pair(1, 0), Pair(-1, 0)
    )

    // 2. Multi-Source BFS
    while (queue.isNotEmpty()) {
        val (r, c) = queue.poll()
        val d = D[r][c]
        // The color associated with the minimum time D[r][c]
        val cPropagating = C_final[r][c] 

        for ((dr, dc) in directions) {
            val nr = r + dr
            val nc = c + dc

            if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                val newD = d + 1L

                if (newD < D[nr][nc]) {
                    // Found a strictly shorter path (New minimum time)
                    D[nr][nc] = newD
                    C_final[nr][nc] = cPropagating
                    queue.add(Pair(nr, nc))

                } else if (newD == D[nr][nc]) {
                    // Collision at minimum time (Tie in distance). Check for maximum color.
                    // Update color if the propagating color is greater.
                    if (cPropagating > C_final[nr][nc]) {
                        C_final[nr][nc] = cPropagating
                        // Following the reference solution structure, we do not re-queue here 
                        // even though the color has changed at the same minimum distance.
                    }
                }
            }
        }
    }

    return C_final
}

